const StaffController: React.FC<{ 
  user: User, 
  tickets: Ticket[], 
  services: Service[], 
  stations: Station[],
  updateTicketStatus: (t: string, s: TicketStatus, st: string) => void 
}> = ({ user, tickets, services, stations, updateTicketStatus }) => {
  const isAdmin = user.role === UserRole.ADMIN || user.role === UserRole.SUPERADMIN;
  const defaultStationId = isAdmin 
    ? (stations.find(s => s.active)?.id || null) 
    : (user.assignedStationId || null);

  const [activeStationId, setActiveStationId] = useState<string | null>(defaultStationId);

  const activeStation = useMemo(() => 
    stations.find(s => s.id === activeStationId),
  [stations, activeStationId]);

  if (!activeStationId || !activeStation) {
    return (
      <div className="h-[500px] flex flex-col items-center justify-center text-slate-400 max-w-lg text-center mx-auto space-y-6 animate-fade-in">
        <div className="w-24 h-24 bg-slate-100 rounded-[2.5rem] flex items-center justify-center text-5xl grayscale opacity-50">🔒</div>
        <h2 className="text-3xl font-black text-slate-900 tracking-tight">Acceso Restringido</h2>
        <p className="text-slate-500 font-medium leading-relaxed italic">Su perfil no cuenta con una estación de trabajo activa vinculada. Contacte con la administración de GESFIL para su asignación.</p>
      </div>
    );
  }

  return (
    <StaffView 
      station={activeStation} 
      allStations={isAdmin ? stations.filter(s => s.active) : []}
      tickets={tickets} 
      services={services} 
      userRole={user.role}
      onStatusUpdate={updateTicketStatus} 
      onSelectStation={(id) => isAdmin && setActiveStationId(id)}
    />
  );
};

const App: React.FC = () => {
  const { 
    state, addTicket, updateTicketStatus, resetSystem, login, logout, 
    addUser, updateUser, deleteUser,
    addService, updateService, deleteService,
    addStation, updateStation, deleteStation
  } = useQmsStore();

  if (!state.currentUser) {
    return <LoginView onLogin={login} />;
  }

  const role = state.currentUser.role;
  const user = state.currentUser;

  return (
    <Router>
      <div className="min-h-screen pb-32 bg-[#f8fafc]">
        <Routes>
          <Route path="/" element={
            [UserRole.TOTEM, UserRole.ADMIN, UserRole.SUPERADMIN].includes(role) 
              ? <TotemView services={state.services.filter(s => s.active)} nextSequence={state.nextSequence} onIssueTicket={addTicket} /> 
              : <Navigate to="/staff" />
          } />

          <Route path="/staff" element={
            [UserRole.STAFF, UserRole.ADMIN, UserRole.SUPERADMIN].includes(role) ? (
              <div className="py-12 px-6">
                <StaffController 
                  user={user}
                  tickets={state.tickets}
                  services={state.services}
                  stations={state.stations}
                  updateTicketStatus={updateTicketStatus}
                />
              </div>
            ) : <Navigate to="/" />
          } />

          <Route path="/display" element={<PublicDisplayView tickets={state.tickets} stations={state.stations} services={state.services} />} />

          <Route path="/admin" element={
            [UserRole.ADMIN, UserRole.SUPERADMIN].includes(role) ? (
              <div className="space-y-4">
                {role === UserRole.ADMIN && (
                   <DashboardView 
                    tickets={state.tickets} 
                    services={state.services} 
                    stations={state.stations} 
                    onToggleService={(id, active) => updateService(id, { active })}
                  />
                )}
                {role === UserRole.SUPERADMIN && (
                   <AdminPanel 
                    state={state}
                    reset={resetSystem} 
                    userRole={role} 
                    users={state.users}
                    onAddUser={addUser}
                    onUpdateUser={updateUser}
                    onDeleteUser={deleteUser}
                    services={state.services}
                    onAddService={addService}
                    onUpdateService={updateService}
                    onDeleteService={deleteService}
                    stations={state.stations}
                    onAddStation={addStation}
                    onUpdateStation={updateStation}
                    onDeleteStation={deleteStation}
                  />
                )}
              </div>
            ) : <Navigate to="/" />
          } />

          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
        <Nav role={role} logout={logout} currentUser={state.currentUser} />
      </div>
    </Router>
  );
};

export default App;

import React, { useState } from 'react';
import { User, UserRole, Station } from '../types';

interface UserManagementViewProps {
  users: User[];
  onAdd: (userData: Omit<User, 'id'>) => void;
  onUpdate: (id: string, updates: Partial<User>) => void;
  onDelete: (id: string) => void;
  stations: Station[];
}

const UserManagementView: React.FC<UserManagementViewProps> = ({ users, onAdd, onUpdate, onDelete, stations }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);

  const [formData, setFormData] = useState({
    name: '',
    username: '',
    password: '',
    role: UserRole.STAFF,
    assignedStationId: ''
  });

  const handleOpenModal = (user?: User) => {
    if (user) {
      setEditingUser(user);
      setFormData({
        name: user.name,
        username: user.username,
        password: user.password || '',
        role: user.role,
        assignedStationId: user.assignedStationId || ''
      });
    } else {
      setEditingUser(null);
      setFormData({ name: '', username: '', password: '', role: UserRole.STAFF, assignedStationId: '' });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const dataToSend: any = { ...formData };

    if (dataToSend.role !== UserRole.STAFF) {
      dataToSend.assignedStationId = undefined;
    }

    if (editingUser) {
      onUpdate(editingUser.id, dataToSend);
    } else {
      onAdd(dataToSend);
    }
    setIsModalOpen(false);
  };

  return (
    <div className="flex flex-col h-full bg-white">
      <div className="p-10 border-b border-slate-100 flex flex-col sm:flex-row justify-between items-start sm:items-center bg-slate-50/30 gap-6">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Directorio de Identidades</h3>
          <p className="text-[11px] text-slate-500 font-bold mt-1 uppercase tracking-[0.2em]">Gestión de privilegios y vinculación de terminales</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="bg-indigo-600 text-white px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-900 transition-all shadow-2xl shadow-indigo-100 flex items-center gap-3 active:scale-95"
        >
          <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="M12 5v14"/></svg>
          Registrar Operador
        </button>
      </div>

      <div className="p-10 flex-grow overflow-y-auto custom-scrollbar">
        <div className="grid grid-cols-1 md:grid-cols-2 2xl:grid-cols-3 gap-6">
          {users.map(user => {
            const station = stations.find(s => s.id === user.assignedStationId);
            return (
              <div key={user.id} className="group relative bg-white border border-slate-100 rounded-[2.5rem] p-8 hover:border-indigo-200 hover:shadow-2xl transition-all duration-500 overflow-hidden">
                 <div className="absolute top-0 right-0 w-24 h-24 bg-slate-50 rounded-full -translate-y-12 translate-x-12 opacity-0 group-hover:opacity-100 transition-all duration-700"></div>

                 <div className="flex items-center gap-6 relative z-10">
                    <div className={`w-20 h-20 rounded-[1.75rem] flex items-center justify-center text-2xl font-black text-white shadow-2xl ${
                      user.role === UserRole.SUPERADMIN ? 'bg-slate-900' :
                      user.role === UserRole.ADMIN ? 'bg-indigo-600' : 'bg-emerald-600'
                    } ring-4 ring-white`}>
                      {user.name[0]}
                    </div>
                    <div className="flex-grow min-w-0">
                       <div className="flex items-center justify-between mb-1.5">
                          <h4 className="text-xl font-black text-slate-900 truncate pr-2">{user.name}</h4>
                       </div>
                       <div className="flex flex-wrap gap-2">
                          <span className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest ${
                            user.role === UserRole.SUPERADMIN ? 'bg-slate-900 text-white' :
                            user.role === UserRole.ADMIN ? 'bg-indigo-50 text-indigo-600' : 'bg-emerald-50 text-emerald-600'
                          }`}>
                            {user.role}
                          </span>
                          <span className="px-3 py-1.5 rounded-xl text-[9px] font-black bg-slate-100 text-slate-400 uppercase tracking-widest">
                            @{user.username}
                          </span>
                       </div>
                    </div>
                 </div>

                 <div className="mt-8 pt-6 border-t border-slate-50 flex items-center justify-between relative z-10">
                    <div className="flex flex-col">
                       <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Terminal</span>
                       <span className="text-[10px] font-bold text-slate-700 truncate max-w-[120px]">
                         {user.role === UserRole.STAFF ? (station?.name || 'No Vinculado') : '---'}
                       </span>
                    </div>
