                  className="flex-1 py-5 bg-indigo-600 text-white text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100"
                >
                  Confirmar Nodo
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

