import { useState, useEffect, useCallback } from 'react';
import { Ticket, TicketStatus, Service, Station, QmsState, User, UserRole } from '../types';
import { INITIAL_SERVICES, INITIAL_STATIONS } from '../constants';

const DEFAULT_USERS: User[] = [
  { id: 'u1', username: 'superadmin', password: '123', name: 'Super Administrador', role: UserRole.SUPERADMIN },
  { id: 'u2', username: 'admin', password: '123', name: 'Gestor Operativo', role: UserRole.ADMIN },
  { id: 'u3', username: 'staff1', password: '123', name: 'Operario 01', role: UserRole.STAFF, assignedStationId: 's1' },
  { id: 'u4', username: 'totem', password: '123', name: 'Tótem Entrada', role: UserRole.TOTEM },
];

const STORAGE_KEY = 'gesfil_qms_v2_core';

export const useQmsStore = () => {
  const getInitialState = (): QmsState => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      if (saved) {
        const parsed = JSON.parse(saved);
        return {
          ...parsed,
          services: (parsed.services || INITIAL_SERVICES).map((s: any) => ({
            ...s,
            active: typeof s.active === 'boolean' ? s.active : true
          })),
          stations: (parsed.stations || INITIAL_STATIONS).map((s: any) => ({
            ...s,
            active: typeof s.active === 'boolean' ? s.active : true,
            serviceIds: Array.isArray(s.serviceIds) ? s.serviceIds : []
          })),
          users: (parsed.users || DEFAULT_USERS).map((u: any) => ({
            ...u,
            role: Object.values(UserRole).includes(u.role) ? u.role : UserRole.STAFF
          })),
          tickets: Array.isArray(parsed.tickets) ? parsed.tickets : [],
          currentUser: parsed.currentUser || null,
          nextSequence: parsed.nextSequence || {}
        };
      }
    } catch (e) {
      console.error("Storage Recovery Error:", e);
    }
    return {
      services: INITIAL_SERVICES,
      stations: INITIAL_STATIONS,
      tickets: [],
      nextSequence: INITIAL_SERVICES.reduce((acc, s) => ({ ...acc, [s.id]: 101 }), {}),
      users: DEFAULT_USERS,
      currentUser: null,
    };
  };

  const [state, setState] = useState<QmsState>(getInitialState);

  // Sincronización Multi-Pestaña (Crucial para QMS en red local)
  useEffect(() => {
    const handleStorageChange = (e: StorageEvent) => {
      if (e.key === STORAGE_KEY && e.newValue) {
        setState(JSON.parse(e.newValue));
      }
    };
    window.addEventListener('storage', handleStorageChange);
    return () => window.removeEventListener('storage', handleStorageChange);
  }, []);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }, [state]);

  const login = useCallback((username: string, password?: string) => {
    const user = state.users.find(u => 
      u.username.toLowerCase() === username.trim().toLowerCase() && 
      u.password === password
    );
    if (user) {
      setState(prev => ({ ...prev, currentUser: user }));
      return true;
    }
    return false;
  }, [state.users]);

  const logout = useCallback(() => setState(prev => ({ ...prev, currentUser: null })), []);

  const addTicket = useCallback((serviceId: string) => {
    setState(prev => {
      const service = prev.services.find(s => s.id === serviceId);
      if (!service || !service.active) return prev;

      const sequence = prev.nextSequence[serviceId] || 101;
      const newTicket: Ticket = {
        id: crypto.randomUUID(),
        code: `${service.prefix}-${sequence}`,
        serviceId,
        status: TicketStatus.WAITING,
        createdAt: Date.now(),
        metadata: { recalledCount: 0 }
      };

      return {
        ...prev,
        tickets: [...prev.tickets, newTicket],
        nextSequence: { ...prev.nextSequence, [serviceId]: sequence + 1 }
      };
    });
  }, []);

  const updateTicketStatus = useCallback((ticketId: string, newStatus: TicketStatus, stationId: string) => {
    setState(prev => {
      const index = prev.tickets.findIndex(t => t.id === ticketId);
      if (index === -1) return prev;

      const ticket = prev.tickets[index];
      const station = prev.stations.find(s => s.id === stationId);

      // Bloqueo de Seguridad: No permitir llamar tickets si el módulo no está activo
      if (station && !station.active && newStatus === TicketStatus.CALLING) return prev;

      // Validación de Seguridad: Un ticket ya en atención no puede ser capturado por otro módulo
      if (newStatus === TicketStatus.CALLING && ticket.status !== TicketStatus.WAITING && ticket.stationId !== stationId) {
        return prev;
      }

      // Máquina de Estados Definida
      const isLegal = 
        (ticket.status === TicketStatus.WAITING && newStatus === TicketStatus.CALLING) ||
        (ticket.status === TicketStatus.CALLING && [TicketStatus.CALLING, TicketStatus.ATTENDING, TicketStatus.CANCELLED].includes(newStatus)) ||
        (ticket.status === TicketStatus.ATTENDING && [TicketStatus.COMPLETED, TicketStatus.CANCELLED].includes(newStatus));

      if (!isLegal) return prev;

      const updatedTickets = [...prev.tickets];
      const updates: Partial<Ticket> = { status: newStatus };

      if (newStatus === TicketStatus.CALLING) {
        updates.calledAt = Date.now();
        updates.stationId = stationId;
        updates.metadata = { 
          ...ticket.metadata, 
          recalledCount: (ticket.metadata?.recalledCount || 0) + 1 
        };
      } else if (newStatus === TicketStatus.ATTENDING) {
        updates.startedAt = ticket.startedAt || Date.now();
      } else if ([TicketStatus.COMPLETED, TicketStatus.CANCELLED].includes(newStatus)) {
        updates.endedAt = Date.now();
      }

      updatedTickets[index] = { ...ticket, ...updates };
      return { ...prev, tickets: updatedTickets };
    });
  }, []);

  const addUser = (u: Omit<User, 'id'>) => setState(p => ({ ...p, users: [...p.users, { ...u, id: crypto.randomUUID() }] }));

  const updateUser = (id: string, u: Partial<User>) => setState(p => {
    const updatedUsers = p.users.map(x => {
      if (x.id === id) {
        const newUser = { ...x, ...u };
        if (newUser.role !== UserRole.STAFF) newUser.assignedStationId = undefined;
        return newUser;
      }
      return x;
    });
    return { ...p, users: updatedUsers };
  });

  const deleteUser = (id: string) => setState(p => ({ ...p, users: p.users.filter(x => x.id !== id) }));

  const addService = (s: Omit<Service, 'id'>) => {
    const id = crypto.randomUUID();
    setState(p => ({ ...p, services: [...p.services, { ...s, id }], nextSequence: { ...p.nextSequence, [id]: 101 } }));
  };

  const updateService = (id: string, s: Partial<Service>) => setState(p => ({ ...p, services: p.services.map(x => x.id === id ? { ...x, ...s } : x) }));

  const deleteService = (id: string) => setState(p => ({
    ...p,
    services: p.services.filter(x => x.id !== id),
    tickets: p.tickets.filter(t => t.serviceId !== id), // Limpiar tickets huérfanos
    stations: p.stations.map(st => ({ ...st, serviceIds: st.serviceIds.filter(sid => sid !== id) }))
  }));

  const addStation = (s: Omit<Station, 'id'>) => setState(p => ({ ...p, stations: [...p.stations, { ...s, id: crypto.randomUUID() }] }));

  const updateStation = (id: string, s: Partial<Station>) => setState(p => ({ ...p, stations: p.stations.map(x => x.id === id ? { ...x, ...s } : x) }));

  const deleteStation = (id: string) => setState(p => ({ 
    ...p, 
    stations: p.stations.filter(x => x.id !== id),
    users: p.users.map(u => u.assignedStationId === id ? { ...u, assignedStationId: undefined } : u)
  }));

  const resetSystem = () => {
    if (confirm("¿Confirmar purga diaria? Esta acción reiniciará los turnos a 101 y vaciará la base de datos de tickets del día.")) {
      setState(p => ({ 
        ...p, 
        tickets: [], 
        nextSequence: p.services.reduce((acc, s) => ({ ...acc, [s.id]: 101 }), {}) 
      }));
    }
  };

  return { 
    state, login, logout, addTicket, updateTicketStatus, resetSystem, 
    addUser, updateUser, deleteUser, addService, updateService, deleteService, 
    addStation, updateStation, deleteStation 
  };
};

import React, { useMemo, useState, useEffect } from 'react';
import { Ticket, Service, Station, TicketStatus } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import TicketTraceabilityModal from './TicketTraceabilityModal';
import { analyzeOperationalHealth } from '../services/gemini';

interface DashboardViewProps {
  tickets: Ticket[];
  services: Service[];
  stations: Station[];
  onToggleService?: (id: string, active: boolean) => void;
}

const DashboardView: React.FC<DashboardViewProps> = ({ tickets, services, stations, onToggleService }) => {
  const [inspectingTicket, setInspectingTicket] = useState<Ticket | null>(null);
  const [aiInsight, setAiInsight] = useState<string>("Sincronizando con motor de inteligencia...");

  useEffect(() => {
    if (tickets.length > 3) {
      analyzeOperationalHealth(tickets, services).then(setAiInsight);
    }
  }, [tickets.length, services]);

  const stats = useMemo(() => {
    const total = tickets.length;
    const completed = tickets.filter(t => t.status === TicketStatus.COMPLETED).length;
    const waiting = tickets.filter(t => t.status === TicketStatus.WAITING).length;
    const cancelled = tickets.filter(t => t.status === TicketStatus.CANCELLED).length;

    // Solo mostrar servicios que existen en la configuración actual
    const dataByService = services.map(s => {
      const sTickets = tickets.filter(t => t.serviceId === s.id);
      return {
        name: s.name,
        value: sTickets.length,
        color: s.color || '#4f46e5'
      };
    }).filter(item => item.value > 0 || services.some(s => s.name === item.name && s.active));

    const recent = [...tickets].sort((a, b) => b.createdAt - a.createdAt).slice(0, 10);

    return { total, completed, waiting, cancelled, dataByService, recent };
  }, [tickets, services]);

  return (
    <div className="max-w-7xl mx-auto px-6 py-12 space-y-10 animate-fade-in">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center border-b border-slate-200 pb-10 gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">GESFIL Business Hub</h1>
          <p className="text-slate-500 font-medium">Infraestructura de Gestión en Tiempo Real</p>
        </div>

        <div className="bg-indigo-900 text-indigo-100 p-6 rounded-[2.5rem] shadow-2xl border border-indigo-700 max-w-md relative overflow-hidden group">
           <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:scale-125 transition-transform">✨</div>
           <p className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-400 mb-2">IA Insights (Gemini)</p>
           <p className="text-xs font-bold leading-relaxed">{aiInsight}</p>
        </div>
      </header>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Total Turnos', value: stats.total, color: 'text-slate-900' },
          { label: 'Atendidos', value: stats.completed, color: 'text-emerald-500' },
          { label: 'En Cola', value: stats.waiting, color: 'text-amber-500' },
          { label: 'Cancelados', value: stats.cancelled, color: 'text-rose-500' },
        ].map((k, i) => (
          <div key={i} className="bg-white p-8 rounded-[2.5rem] border border-slate-200 shadow-sm transition-all hover:-translate-y-1">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">{k.label}</p>
            <p className={`text-4xl font-black ${k.color}`}>{k.value}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-8 bg-white p-10 rounded-[3.5rem] border border-slate-200 shadow-sm">
          <h3 className="text-xl font-black text-slate-900 mb-10">Distribución por Servicio</h3>
          <div className="h-[350px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.dataByService}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 700}} />
                <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10}} />
                <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '24px', border: 'none', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)'}} />
                <Bar dataKey="value" radius={[12, 12, 12, 12]} barSize={45}>
                  {stats.dataByService.map((e, idx) => <Cell key={idx} fill={e.color} />)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="lg:col-span-4 bg-slate-900 text-white p-8 rounded-[3.5rem] shadow-2xl relative overflow-hidden">
           <h3 className="text-lg font-black mb-8 uppercase tracking-widest text-indigo-400">Trazabilidad Reciente</h3>
           <div className="space-y-4">
              {stats.recent.length > 0 ? stats.recent.map(t => (
                <div key={t.id} className="flex items-center justify-between p-4 bg-white/5 rounded-2xl border border-white/5 group hover:bg-white/10 transition-all cursor-pointer" onClick={() => setInspectingTicket(t)}>
                   <div>
                      <p className="text-sm font-black text-white">{t.code}</p>
                      <p className="text-[9px] text-slate-500 uppercase font-black">{new Date(t.createdAt).toLocaleTimeString()}</p>
                   </div>
                   <div className={`w-2 h-2 rounded-full ${t.status === 'COMPLETED' ? 'bg-emerald-500' : 'bg-indigo-500'}`}></div>
                </div>
              )) : (
                <div className="py-10 text-center text-slate-500 italic text-sm">No hay transacciones hoy</div>
              )}
           </div>
        </div>
      </div>

      {inspectingTicket && (
        <TicketTraceabilityModal 
          ticket={inspectingTicket}
          service={services.find(s => s.id === inspectingTicket.serviceId)}
          station={stations.find(st => st.id === inspectingTicket.stationId)}
          onClose={() => setInspectingTicket(null)}
        />
      )}
    </div>
  );
};

export default DashboardView;
